import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import './ProfilePage.css';

const ProfilePage = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('overview');
  const [isEditing, setIsEditing] = useState(false);
  const [profileData, setProfileData] = useState({
    username: user?.username || '',
    email: user?.email || '',
    bio: 'Любитель манги и аниме. Читаю все подряд!',
    avatar: null
  });

  const tabs = [
    { id: 'overview', label: 'Обзор', icon: 'fa-home' },
    { id: 'activity', label: 'Активность', icon: 'fa-chart-line' },
    { id: 'library', label: 'Библиотека', icon: 'fa-book' },
    { id: 'reviews', label: 'Рецензии', icon: 'fa-star' },
    { id: 'settings', label: 'Настройки', icon: 'fa-cog' }
  ];

  const handleSave = () => {
    setIsEditing(false);
    // Здесь будет логика сохранения данных
    console.log('Saving profile:', profileData);
  };

  if (!user) {
    return (
      <div className="profile-page">
        <div className="not-logged-in">
          <h2>Пожалуйста, войдите в систему</h2>
          <p>Чтобы просмотреть профиль, необходимо войти в аккаунт</p>
        </div>
      </div>
    );
  }

  return (
    <div className="profile-page">
      <div className="profile-header">
        <div className="profile-cover">
          <div className="cover-overlay"></div>
        </div>
        
        <div className="profile-info">
          <div className="avatar-section">
            <div className="avatar-container">
              <div className="avatar">
                {user.avatar ? (
                  <img src={user.avatar} alt={user.username} />
                ) : (
                  <i className="fas fa-user"></i>
                )}
              </div>
              <div className="level-badge">
                Уровень {user.level}
              </div>
            </div>
            <div className="profile-stats">
              <div className="stat">
                <span className="stat-value">{user.points}</span>
                <span className="stat-label">Очков</span>
              </div>
              <div className="stat">
                <span className="stat-value">245</span>
                <span className="stat-label">Прочитано</span>
              </div>
              <div className="stat">
                <span className="stat-value">89</span>
                <span className="stat-label">Рецензий</span>
              </div>
            </div>
          </div>
          
          <div className="profile-details">
            <div className="profile-header-row">
              {isEditing ? (
                <input
                  type="text"
                  value={profileData.username}
                  onChange={(e) => setProfileData({...profileData, username: e.target.value})}
                  className="username-input"
                />
              ) : (
                <h1 className="username">{user.username}</h1>
              )}
              
              {isEditing ? (
                <div className="edit-buttons">
                  <button className="save-btn" onClick={handleSave}>
                    Сохранить
                  </button>
                  <button className="cancel-btn" onClick={() => setIsEditing(false)}>
                    Отмена
                  </button>
                </div>
              ) : (
                <button className="edit-btn" onClick={() => setIsEditing(true)}>
                  <i className="fas fa-edit"></i>
                  Редактировать профиль
                </button>
              )}
            </div>
            
            <div className="profile-meta">
              <span className="meta-item">
                <i className="fas fa-envelope"></i>
                {isEditing ? (
                  <input
                    type="email"
                    value={profileData.email}
                    onChange={(e) => setProfileData({...profileData, email: e.target.value})}
                    className="email-input"
                  />
                ) : (
                  user.email
                )}
              </span>
              <span className="meta-item">
                <i className="fas fa-calendar"></i>
                На сайте с 15 янв 2023
              </span>
              <span className="meta-item">
                <i className="fas fa-clock"></i>
                Был в сети 2 часа назад
              </span>
            </div>
            
            <div className="profile-bio">
              <h3>О себе</h3>
              {isEditing ? (
                <textarea
                  value={profileData.bio}
                  onChange={(e) => setProfileData({...profileData, bio: e.target.value})}
                  className="bio-input"
                  rows="4"
                />
              ) : (
                <p>{profileData.bio}</p>
              )}
            </div>
          </div>
        </div>
      </div>
      
      <div className="profile-tabs">
        <div className="tabs-nav">
          {tabs.map(tab => (
            <button
              key={tab.id}
              className={`tab-btn ${activeTab === tab.id ? 'active' : ''}`}
              onClick={() => setActiveTab(tab.id)}
            >
              <i className={`fas ${tab.icon}`}></i>
              {tab.label}
            </button>
          ))}
        </div>
        
        <div className="tab-content">
          {activeTab === 'overview' && (
            <div className="overview-tab">
              <div className="recent-activity">
                <h3>Недавняя активность</h3>
                <div className="activity-list">
                  {[
                    { action: 'Прочитал главу', title: 'Berserk #363', time: '2 часа назад' },
                    { action: 'Оставил рецензию', title: 'Solo Leveling', time: '5 часов назад' },
                    { action: 'Добавил в библиотеку', title: 'Tower of God', time: '1 день назад' },
                    { action: 'Получил достижение', title: 'Читатель дня', time: '2 дня назад' }
                  ].map((activity, index) => (
                    <div key={index} className="activity-item">
                      <div className="activity-icon">
                        <i className={`fas fa-${activity.action.includes('Прочитал') ? 'book' : 
                                        activity.action.includes('Рецензия') ? 'star' : 
                                        activity.action.includes('Добавил') ? 'plus' : 'trophy'}`}></i>
                      </div>
                      <div className="activity-info">
                        <span className="activity-action">{activity.action}</span>
                        <span className="activity-title">{activity.title}</span>
                      </div>
                      <span className="activity-time">{activity.time}</span>
                    </div>
                  ))}
                </div>
              </div>
              
              <div className="achievements">
                <h3>Достижения</h3>
                <div className="achievements-grid">
                  {[
                    { title: 'Новичок', desc: 'Прочитано 10 глав', icon: 'fa-seedling', earned: true },
                    { title: 'Читатель', desc: 'Прочитано 50 глав', icon: 'fa-book-reader', earned: true },
                    { title: 'Знаток', desc: 'Прочитано 200 глав', icon: 'fa-graduation-cap', earned: false },
                    { title: 'Эксперт', desc: 'Прочитано 500 глав', icon: 'fa-crown', earned: false }
                  ].map((ach, index) => (
                    <div key={index} className={`achievement-card ${ach.earned ? 'earned' : 'locked'}`}>
                      <div className="achievement-icon">
                        <i className={`fas ${ach.icon}`}></i>
                      </div>
                      <div className="achievement-info">
                        <h4>{ach.title}</h4>
                        <p>{ach.desc}</p>
                      </div>
                      {ach.earned ? (
                        <i className="fas fa-check earned-badge"></i>
                      ) : (
                        <i className="fas fa-lock locked-badge"></i>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
          
          {activeTab === 'library' && (
            <div className="library-tab">
              <h3>Моя библиотека</h3>
              <p>В разработке...</p>
            </div>
          )}
          
          {activeTab === 'settings' && (
            <div className="settings-tab">
              <h3>Настройки</h3>
              <p>В разработке...</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;
